/**
 * SPEC-021: coste de IA en el panel del asistente (mitad UI) — línea de uso de
 * sesión, Alert de pausa por límite con su copy literal, "Reanudar asistente"
 * y aislamiento de grabación/transcripción/guión durante la pausa.
 * Generated by QA Dev agent.
 *
 * Montado vía InterviewDetailPage con la grabación en curso (mocks del spike,
 * arnés SPEC-016) y eventos inyectados con emitAssistantUpdate. SPEC-019: el
 * arranque atraviesa el aviso de consentimiento.
 */
import { act, render, screen, waitFor, within, type RenderResult } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { Toaster } from '@/components/ui/sonner'
import { TooltipProvider } from '@/components/ui/tooltip'
import { InterviewDetailPage } from '@/pages/InterviewDetailPage'
import {
  acquireMicrophoneStream,
  acquireSystemAudioStream,
  listAudioInputDevices
} from '@/services/captureService'
import { getPermissionsStatus } from '@/services/permissionsService'
import type { AssistantSuggestion } from '@/types/assistant'
import type { AiUsage, Company, Interview } from '@/types/domain'
import { createFakeAudioStream } from '../../helpers/fakeMediaStream'
import { installMockApi, type MockApiHandle } from '../../helpers/mockApi'

vi.mock('@/services/permissionsService', () => ({
  getPermissionsStatus: vi.fn(),
  requestMicrophoneAccess: vi.fn(),
  openPrivacySettings: vi.fn()
}))

vi.mock('@/services/captureService', () => ({
  DEFAULT_DEVICE_ID: '__default__',
  acquireMicrophoneStream: vi.fn(),
  acquireSystemAudioStream: vi.fn(),
  listAudioInputDevices: vi.fn(),
  stopStream: vi.fn()
}))

vi.mock('@/services/wavRecorderService', () => ({
  CAPTURE_SAMPLE_RATE: 16000,
  WavRecorderService: class {
    start = vi.fn()
    stop = vi.fn()
    getLevels = vi.fn(() => ({ microphone: 0, system: 0 }))
    readonly durationSeconds = 0
    readonly samplesWritten = 0
  }
}))

let mockApi: MockApiHandle

const COMPANY: Company = {
  id: 'c-1',
  discoveryId: 'd-1',
  name: 'Acme Corp',
  website: null,
  linkedinUrl: null,
  createdAt: '2026-07-02T12:00:00.000Z',
  updatedAt: '2026-07-02T12:00:00.000Z'
}

const INTERVIEW: Interview = {
  id: 'i-1',
  discoveryId: 'd-1',
  companyId: 'c-1',
  contactId: null,
  templateId: 'tpl-1',
  title: 'Discovery con Acme',
  status: 'prepared',
  scriptMarkdown: '# Guión adaptado\nPregunta clave para la llamada',
  objectives: [],
  wavPath: null,
  transcriptPath: null,
  createdAt: '2026-07-04T10:00:00.000Z',
  updatedAt: '2026-07-04T10:00:00.000Z'
}

function usage(overrides: Partial<AiUsage> = {}): AiUsage {
  return { calls: 4, inputTokens: 12_000, outputTokens: 2_400, estimatedCostUsd: 0.12, ...overrides }
}

function suggestion(): AssistantSuggestion {
  return {
    action: 'continue',
    suggestedQuestion: '¿Cuándo fue la última vez que pasó?',
    reason: 'Ya hay material concreto para avanzar',
    alarms: []
  }
}

const PAUSED_COPY =
  'Límite de coste alcanzado ($1.00). El asistente está en pausa; la grabación y la transcripción continúan.'

function renderDetail(): RenderResult {
  return render(
    <TooltipProvider>
      <MemoryRouter initialEntries={['/discoveries/d-1/companies/c-1/interviews/i-1']}>
        <Routes>
          <Route
            path="/discoveries/:discoveryId/companies/:companyId/interviews/:interviewId"
            element={<InterviewDetailPage />}
          />
        </Routes>
      </MemoryRouter>
      <Toaster />
    </TooltipProvider>
  )
}

/** Arranca la grabación atravesando el aviso de consentimiento (SPEC-019). */
async function startRecording(user: ReturnType<typeof userEvent.setup>): Promise<void> {
  await user.click(await screen.findByRole('button', { name: 'Iniciar grabación' }))
  const consent = await screen.findByRole('alertdialog')
  await user.click(within(consent).getByRole('button', { name: 'Entendido, iniciar grabación' }))
  await screen.findByRole('button', { name: 'Detener' })
}

/** Emite el evento de pausa por límite (SPEC-021) con el usage de la sesión. */
function emitPaused(): void {
  act(() => {
    mockApi.emitAssistantUpdate({
      state: 'paused',
      objectivesMet: [],
      pauseLimitUsd: 1,
      usage: usage()
    })
  })
}

beforeEach(() => {
  vi.clearAllMocks()
  window.localStorage.clear()
  mockApi = installMockApi()
  vi.mocked(mockApi.api.db.getCompany).mockResolvedValue({ ok: true, data: COMPANY })
  vi.mocked(mockApi.api.db.getInterview).mockResolvedValue({ ok: true, data: INTERVIEW })
  vi.mocked(mockApi.api.llm.getStatus).mockResolvedValue({
    ok: true,
    data: { hasAnthropicKey: true }
  })
  vi.mocked(listAudioInputDevices).mockResolvedValue([])
  vi.mocked(getPermissionsStatus).mockResolvedValue({
    microphone: 'granted',
    systemAudio: 'granted'
  })
  vi.mocked(acquireMicrophoneStream).mockResolvedValue(createFakeAudioStream().stream)
  vi.mocked(acquireSystemAudioStream).mockResolvedValue(createFakeAudioStream().stream)
  // Auto-stop al desmontar (cleanup de RecordingSection): resolución mínima
  vi.mocked(mockApi.api.recording.stop).mockResolvedValue({
    filePath: '/tmp/maurya-recordings/entrevista.wav',
    durationSeconds: 5,
    sizeBytes: 44,
    sampleRate: 16000,
    channels: 2,
    transcriptPath: null,
    latency: null,
    interview: null
  })
})

describe('AssistantPanel (coste de IA SPEC-021)', () => {
  // SPEC-021 · AC-06
  it('shows the discreet session line "IA: N llamadas · ~$X.XX" updated after each analysis', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)

    // Antes del primer análisis la línea no existe
    expect(screen.queryByTestId('assistant-usage-line')).not.toBeInTheDocument()

    act(() => {
      mockApi.emitAssistantUpdate({
        state: 'active',
        suggestion: suggestion(),
        objectivesMet: [],
        usage: usage()
      })
    })
    expect(await screen.findByTestId('assistant-usage-line')).toHaveTextContent(
      'IA: 4 llamadas · ~$0.12'
    )

    // Tras el siguiente análisis la línea se actualiza
    act(() => {
      mockApi.emitAssistantUpdate({
        state: 'active',
        suggestion: suggestion(),
        objectivesMet: [],
        usage: usage({ calls: 5, estimatedCostUsd: 0.15 })
      })
    })
    await waitFor(() =>
      expect(screen.getByTestId('assistant-usage-line')).toHaveTextContent(
        'IA: 5 llamadas · ~$0.15'
      )
    )
  })

  // SPEC-021 · AC-11 (UI: Alert de pausa con el copy literal y el botón)
  it('replaces the suggestion with the paused alert showing the exact limit copy and the "Reanudar asistente" button', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)
    act(() => {
      mockApi.emitAssistantUpdate({
        state: 'active',
        suggestion: suggestion(),
        objectivesMet: [],
        usage: usage()
      })
    })
    await screen.findByText('¿Cuándo fue la última vez que pasó?')

    emitPaused()

    const alert = await screen.findByTestId('assistant-paused-alert')
    expect(alert).toHaveTextContent(PAUSED_COPY)
    expect(within(alert).getByRole('button', { name: 'Reanudar asistente' })).toBeInTheDocument()
    // El Alert sustituye a la sugerencia (información persistente con acción)
    expect(screen.queryByText('¿Cuándo fue la última vez que pasó?')).not.toBeInTheDocument()
    // La línea de uso de sesión sigue visible en pausa
    expect(screen.getByTestId('assistant-usage-line')).toHaveTextContent('IA: 4 llamadas · ~$0.12')
  })

  // SPEC-021 · AC-12 (UI: Reanudar → assistant.resume y el aviso desaparece)
  it('calls assistant.resume on "Reanudar asistente" and clears the alert when the assistant becomes active again', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)
    emitPaused()
    const alert = await screen.findByTestId('assistant-paused-alert')

    await user.click(within(alert).getByRole('button', { name: 'Reanudar asistente' }))
    expect(vi.mocked(mockApi.api.assistant.resume)).toHaveBeenCalledTimes(1)

    // Main confirma con el evento de vuelta: el aviso desaparece y se analiza
    act(() => {
      mockApi.emitAssistantUpdate({
        state: 'active',
        suggestion: suggestion(),
        objectivesMet: [],
        usage: usage({ calls: 5, estimatedCostUsd: 0.45 })
      })
    })
    await waitFor(() =>
      expect(screen.queryByTestId('assistant-paused-alert')).not.toBeInTheDocument()
    )
    expect(screen.getByText('¿Cuándo fue la última vez que pasó?')).toBeInTheDocument()
  })

  // SPEC-021 · AC-13 (UI: la pausa no afecta a grabación, transcripción ni guión)
  it('keeps the recording, the live transcription and the visible script untouched while paused by limit', async () => {
    const user = userEvent.setup()
    renderDetail()
    await startRecording(user)
    emitPaused()
    await screen.findByTestId('assistant-paused-alert')

    // La transcripción en vivo sigue llegando y pintándose
    act(() => {
      mockApi.emitTranscriptionStatus({ status: 'active' })
      mockApi.emitTranscriptionResult({
        channel: 'mic',
        text: 'Seguimos hablando con el asistente en pausa',
        startMs: 1000,
        endMs: 2000,
        receivedAtMs: 2100,
        isFinal: true,
        speaker: 0,
        offsetSeconds: 1
      })
    })
    expect(
      await screen.findByText('Seguimos hablando con el asistente en pausa')
    ).toBeInTheDocument()
    expect(screen.getByText('Transcribiendo')).toBeInTheDocument()
    // La grabación sigue operativa (cronómetro + Detener) y el guión legible
    expect(screen.getByText('00:00')).toBeInTheDocument()
    expect(screen.getByRole('button', { name: 'Detener' })).toBeInTheDocument()
    expect(screen.getByRole('heading', { name: 'Guión' })).toBeInTheDocument()
    expect(screen.getByText(/Pregunta clave para la llamada/)).toBeInTheDocument()
  })
})
